class Solution:
    def findSubstring(self, s, words):
        from collections import Counter
        wlen = len(words[0])
        total = wlen * len(words)
        need = Counter(words)
        res = []
        for i in range(len(s) - total + 1):
            chunks = [s[i + j * wlen:i + (j + 1) * wlen] for j in range(len(words))]
            if Counter(chunks) == need:
                res.append(i)
        return res

