var findSubstring = function(s, words) {
    const wlen = words[0].length;
    const k = words.length;
    const need = new Map();
    for (const w of words) need.set(w, (need.get(w) || 0) + 1);
    const n = s.length;
    const res = [];
    for (let offset = 0; offset < wlen; offset++) {
        let left = offset, count = 0;
        const window = new Map();
        let j = offset;
        while (j + wlen <= n) {
            const w = s.substring(j, j + wlen);
            j += wlen;
            if (need.has(w)) {
                window.set(w, (window.get(w) || 0) + 1);
                count++;
                while (window.get(w) > need.get(w)) {
                    const lw = s.substring(left, left + wlen);
                    window.set(lw, window.get(lw) - 1);
                    left += wlen;
                    count--;
                }
                if (count === k) {
                    res.push(left);
                    const lw = s.substring(left, left + wlen);
                    window.set(lw, window.get(lw) - 1);
                    left += wlen;
                    count--;
                }
            } else {
                window.clear();
                count = 0;
                left = j;
            }
        }
    }
    return res;
};
